import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, pkg['id'])
                pkgs[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
    return pkgs

bp = extract(b)
ap = extract(a)
all_keys = sorted(set(bp) | set(ap))
print('Changes:')
for k in all_keys:
    bv = bp.get(k, 'N/A')
    av = ap.get(k, 'N/A')
    if bv != av:
        print(f'  {k[0]}: {k[1]} {bv} -> {av}')
print()
print('Unchanged:')
for k in all_keys:
    bv = bp.get(k, 'N/A')
    av = ap.get(k, 'N/A')
    if bv == av:
        print(f'  {k[0]}: {k[1]} {bv}')
"

